/* ============================================================
   DISCOVER UK TRAVEL COMPANIES
   Uses SerpAPI (Google) to find UK travel company websites.
   Required env var: SERPAPI_KEY
   Falls back to a seed list if SERPAPI_KEY is not set.
   ============================================================ */
const serpApiKey = $env.SERPAPI_KEY || '';

const searchQueries = [
  'UK travel agency tour operator holidays site:co.uk',
  'UK independent tour operator package holidays',
  'UK travel company luxury beach holidays',
  'UK adventure travel company tours',
  'UK group travel holidays operator',
  'UK family holiday travel company',
  'UK coach holiday company tours',
  'UK ski holiday specialist operator',
  'UK walking cycling holiday company',
  'UK cruise holiday specialist',
  'UK honeymoon travel company',
  'UK safari holiday operator'
];

// Domains to skip (aggregators, OTAs, social, directories)
const skipPatterns = [
  'tripadvisor', 'trustpilot', 'google', 'facebook', 'wikipedia',
  'yelp', 'indeed', 'linkedin', 'twitter', 'instagram', 'youtube',
  'booking.com', 'expedia', 'airbnb', 'loveholidays', 'on-the-beach',
  'jet2.', 'tui.', 'firstchoice', 'easyjet', 'ryanair', 'thomascook',
  'lastminute', 'kayak', 'skyscanner', 'holidaypirates', 'dealchecker'
];

const companies = [];
const seenDomains = new Set();

if (serpApiKey) {
  for (const query of searchQueries) {
    try {
      const url = `https://serpapi.com/search?api_key=${encodeURIComponent(serpApiKey)}&engine=google&q=${encodeURIComponent(query)}&num=10&gl=uk&hl=en`;
      const res = await fetch(url, { signal: AbortSignal.timeout(15000) });
      if (!res.ok) continue;
      const data = await res.json();
      for (const result of (data.organic_results || [])) {
        try {
          const link = result.link || '';
          if (!link.startsWith('http')) continue;
          const hostname = new URL(link).hostname.replace(/^www\./, '');
          if (seenDomains.has(hostname)) continue;
          if (skipPatterns.some(p => hostname.includes(p))) continue;
          seenDomains.add(hostname);
          // Extract a clean company name from the page title
          const rawTitle = result.title || hostname;
          const name = rawTitle
            .split(/ [-–|:] /)[0]
            .replace(/\(.*?\)/g, '')
            .trim();
          companies.push({ name, domain: hostname, website: link });
        } catch {}
      }
    } catch {}
  }
}

// Fallback: small seed list for testing when SERPAPI_KEY is not set
if (companies.length === 0) {
  return [
    { json: { name: 'Intrepid Travel', domain: 'intrepidtravel.com', website: 'https://www.intrepidtravel.com' } },
    { json: { name: 'Kuoni UK', domain: 'kuoni.co.uk', website: 'https://www.kuoni.co.uk' } },
    { json: { name: 'Cox and Kings', domain: 'coxandkings.co.uk', website: 'https://www.coxandkings.co.uk' } },
    { json: { name: 'Exodus Travels', domain: 'exodustravels.com', website: 'https://www.exodustravels.com' } },
    { json: { name: 'Neilson Holidays', domain: 'neilson.co.uk', website: 'https://www.neilson.co.uk' } }
  ];
}

return companies.map(c => ({ json: c }));

/* ============================================================
   ANALYSE EACH COMPANY
   Step 1 – Firecrawl: scrape the website, detect Meta Pixel ID
             and social media presence.
   Step 2 – Apify (Meta Ad Library): check for active / lapsed ads.
             Uses the same Apify actor as the main app.
   Step 3 – Qualify as a warm outreach lead.

   Required env vars:
     FIRECRAWL_API_KEY  – from https://firecrawl.dev
     APIFY_API_KEY      – from https://apify.com
   ============================================================ */
const company      = $json;
const firecrawlKey = $env.FIRECRAWL_API_KEY || '';
const apifyKey     = $env.APIFY_API_KEY     || '';

// Apify actor: same as used by the main app's search/route.ts
const APIFY_ACTOR_ID = 'ZQyDz7154hrOfrDMK';

// ──────────────────────────────────────────────────────────────
// STEP 1 – Firecrawl website scrape
// ──────────────────────────────────────────────────────────────
let html            = '';
let pageTitle       = '';
let pageDescription = '';
let scrapeSuccess   = false;
let scrapeError     = '';

if (firecrawlKey && company.website) {
  try {
    const fcRes = await fetch('https://api.firecrawl.dev/v1/scrape', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${firecrawlKey}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        url: company.website,
        formats: ['html'],
        waitFor: 2000,
      }),
      signal: AbortSignal.timeout(35000),
    });
    if (fcRes.ok) {
      const fc = await fcRes.json();
      html            = fc?.data?.html        || '';
      pageTitle       = fc?.data?.metadata?.title       || '';
      pageDescription = fc?.data?.metadata?.description || '';
      scrapeSuccess   = fc?.success === true;
    } else {
      scrapeError = `HTTP ${fcRes.status}`;
    }
  } catch (e) {
    scrapeError = String(e?.message || 'Firecrawl timeout/error');
  }
}

// ──────────────────────────────────────────────────────────────
// STEP 2 – Detect Meta Pixel ID in the scraped HTML
// ──────────────────────────────────────────────────────────────
const pixelPatterns = [
  /fbq\s*\(\s*['"]init['"]\s*,\s*['"]?(\d{10,16})['"]?/i,
  /"pixelId"\s*:\s*"(\d{10,16})"/i,
  /facebook\.com\/tr\?id=(\d{10,16})/i,
  /'pixel_id'\s*:\s*'(\d{10,16})'/i,
  /fbPixelId[^\d]+(\d{10,16})/i,
];
let pixelId = null;
for (const pattern of pixelPatterns) {
  const match = html.match(pattern);
  if (match) { pixelId = match[1]; break; }
}

// Detect social presence signals in the HTML
const hasFacebook  = /facebook\.com\/(?!sharer|share|dialog|plugins)[a-zA-Z0-9./_-]{3,}/.test(html);
const hasInstagram = /instagram\.com\/[a-zA-Z0-9._]{3,}/.test(html);
const hasTiktok    = /tiktok\.com\/@[a-zA-Z0-9._]{2,}/.test(html);
const hasTwitter   = /(?:twitter|x)\.com\/[a-zA-Z0-9_]{3,}/.test(html);

// ──────────────────────────────────────────────────────────────
// STEP 3 – Meta Ad Library check via Apify
// ──────────────────────────────────────────────────────────────
let hasActiveAds         = false;
let hasRecentInactiveAds = false;
let totalAdsFound        = 0;
let mostRecentAdDate     = null;
let adSamples            = [];
let adLibraryError       = '';

if (apifyKey) {
  try {
    // Build the same Facebook Ad Library URL that the main app uses
    const libraryUrl = [
      'https://www.facebook.com/ads/library/',
      '?active_status=all',
      '&ad_type=all',
      '&country=GB',
      `&q=${encodeURIComponent(company.name)}`,
      '&search_type=keyword_unordered',
      '&media_type=all',
    ].join('');

    // Start the Apify run (waitForFinish=90 polls until done or 90s)
    const runRes = await fetch(
      `https://api.apify.com/v2/acts/${APIFY_ACTOR_ID}/runs?waitForFinish=90`,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apifyKey}`,
        },
        body: JSON.stringify({ startUrls: [{ url: libraryUrl }], maxResults: 25 }),
        signal: AbortSignal.timeout(100000),
      }
    );

    const runData = await runRes.json();
    if (!runRes.ok || runData?.error) {
      adLibraryError = runData?.error?.message || 'Apify run failed';
    } else {
      const datasetId = runData?.data?.defaultDatasetId;
      if (!datasetId) {
        adLibraryError = 'No Apify dataset returned';
      } else {
        const itemsRes = await fetch(
          `https://api.apify.com/v2/datasets/${datasetId}/items?limit=25`,
          { headers: { 'Authorization': `Bearer ${apifyKey}` }, signal: AbortSignal.timeout(20000) }
        );
        const items = await itemsRes.json();

        if (Array.isArray(items)) {
          totalAdsFound = items.length;
          const twelveMonthsAgo = Date.now() - 365 * 24 * 60 * 60 * 1000;

          for (const ad of items) {
            // Active ad = no endDate
            if (!ad.endDate) hasActiveAds = true;
            const startMs = ad.startDate ? new Date(ad.startDate).getTime() : 0;
            if (startMs > twelveMonthsAgo) hasRecentInactiveAds = true;
            if (!mostRecentAdDate || startMs > new Date(mostRecentAdDate).getTime()) {
              mostRecentAdDate = ad.startDate || null;
            }
          }

          // Top 3 ad samples for context
          adSamples = items.slice(0, 3).map(ad => ({
            id:          String(ad.adArchiveID || ''),
            pageName:    ad.pageName || '',
            body:        (ad.adCreativeBodies || [])[0] || '',
            status:      ad.adStatus || (ad.endDate ? 'INACTIVE' : 'ACTIVE'),
            startDate:   ad.startDate  || null,
            endDate:     ad.endDate    || null,
            platforms:   ad.publisherPlatforms || [],
            snapshotUrl: ad.adSnapshotUrl || '',
          }));
        }
      }
    }
  } catch (e) {
    adLibraryError = String(e?.message || 'Apify error');
  }
}

// ──────────────────────────────────────────────────────────────
// STEP 4 – Lead qualification
// Warm lead profile:
//   ✅ Has Meta Pixel (they track digital conversions)
//   ✅ NOT currently running active Meta ads (spending gap = opportunity)
//   ✅ Evidence of past ad activity OR strong social presence
//      (they understand digital marketing, just not spending right now)
// ──────────────────────────────────────────────────────────────
const hasPixel          = !!pixelId;
const hasSocialPresence = hasFacebook || hasInstagram || hasTiktok;
const hadAdsHistory     = totalAdsFound > 0;

const isQualified = hasPixel && !hasActiveAds && (hadAdsHistory || hasSocialPresence);

// Score the lead (max 100)
let leadScore = 0;
if (hasPixel)              leadScore += 35; // Highest signal: they set up tracking
if (!hasActiveAds)         leadScore += 15; // Not spending = open to outreach
if (hasRecentInactiveAds)  leadScore += 30; // Recent lapse = strong buying intent
if (hadAdsHistory && !hasRecentInactiveAds) leadScore += 10; // Older history
if (hasFacebook)           leadScore += 5;
if (hasInstagram)          leadScore += 5;

const reasonParts = [];
if (hasPixel)                               reasonParts.push(`Meta Pixel found (ID: ${pixelId})`);
if (hasRecentInactiveAds)                   reasonParts.push('ran Meta ads within last 12 months');
if (hadAdsHistory && !hasRecentInactiveAds) reasonParts.push(`${totalAdsFound} historical Meta ad(s)`);
if (!hasActiveAds && hadAdsHistory)         reasonParts.push('currently not running any ads');
if (hasFacebook)                            reasonParts.push('Facebook page linked on site');
if (hasInstagram)                           reasonParts.push('Instagram linked on site');
if (!pixelId && scrapeSuccess)              reasonParts.push('no Meta Pixel detected');

return [{
  json: {
    // Company
    company_name:             company.name,
    domain:                   company.domain,
    website:                  company.website,
    page_title:               pageTitle,
    page_description:         pageDescription,
    // Meta Pixel
    pixel_id:                 pixelId,
    has_pixel:                hasPixel,
    // Social
    has_facebook:             hasFacebook,
    has_instagram:            hasInstagram,
    has_tiktok:               hasTiktok,
    has_twitter:              hasTwitter,
    // Ad Library
    has_active_ads:           hasActiveAds,
    has_recent_inactive_ads:  hasRecentInactiveAds,
    total_ads_found:          totalAdsFound,
    most_recent_ad_date:      mostRecentAdDate,
    ad_samples:               adSamples,
    ad_library_error:         adLibraryError,
    // Lead score
    is_qualified:             isQualified,
    lead_score:               leadScore,
    lead_reason:              reasonParts.join(' | ') || 'Does not meet criteria',
    // Debug
    scrape_success:           scrapeSuccess,
    scrape_error:             scrapeError,
    analysed_at:              new Date().toISOString(),
  }
}];

/* ============================================================
   FORMAT LEAD RECORD
   Produces a clean, CRM-friendly object for each qualified lead.
   Extend this node to push rows to Airtable, Google Sheets,
   HubSpot, Pipedrive, Slack, etc.
   ============================================================ */
const d = $json;

const adStatus =
  d.has_recent_inactive_ads ? 'Ran ads < 12 months ago (inactive now)'
  : d.total_ads_found > 0   ? `${d.total_ads_found} historical ad(s), no recent activity`
  :                           'No Meta ad history found';

return [{
  json: {
    // ── Core identifiers ──────────────────────────────────────
    company_name:     d.company_name,
    website:          d.website,
    domain:           d.domain,
    // ── Lead quality ─────────────────────────────────────────
    lead_score:       d.lead_score,
    lead_reason:      d.lead_reason,
    // ── Meta Pixel ───────────────────────────────────────────
    pixel_id:         d.pixel_id || '',
    has_pixel:        d.has_pixel,
    // ── Ad Library summary ───────────────────────────────────
    ad_status_summary:       adStatus,
    has_active_ads:          d.has_active_ads,
    has_recent_inactive_ads: d.has_recent_inactive_ads,
    total_ads_found:         d.total_ads_found,
    most_recent_ad_date:     d.most_recent_ad_date || '',
    // ── Social presence ──────────────────────────────────────
    has_facebook:    d.has_facebook,
    has_instagram:   d.has_instagram,
    has_tiktok:      d.has_tiktok,
    // ── Page meta ────────────────────────────────────────────
    page_title:       d.page_title,
    page_description: d.page_description,
    // ── Top ad sample (for outreach context) ─────────────────
    top_ad_body:      (d.ad_samples && d.ad_samples[0]) ? d.ad_samples[0].body  : '',
    top_ad_page:      (d.ad_samples && d.ad_samples[0]) ? d.ad_samples[0].pageName : '',
    top_ad_snapshot:  (d.ad_samples && d.ad_samples[0]) ? d.ad_samples[0].snapshotUrl : '',
    // ── Timestamps ───────────────────────────────────────────
    analysed_at:     d.analysed_at,
    // ── Full raw payload (useful for further processing) ─────
    _raw:            d,
  }
}];

/* ============================================================
   BUILD SUMMARY REPORT
   Produces a single object with the full lead list,
   top-10 by score, and headline stats ready for Slack,
   email, Google Sheets, Airtable, etc.
   ============================================================ */
const leads = ($json.leads || []).map(l => l._raw || l);

const stats = {
  total_qualified_leads:    leads.length,
  with_pixel:               leads.filter(l => l.has_pixel).length,
  with_recent_ad_history:   leads.filter(l => l.has_recent_inactive_ads).length,
  no_ad_history:            leads.filter(l => l.total_ads_found === 0).length,
  with_facebook:            leads.filter(l => l.has_facebook).length,
  with_instagram:           leads.filter(l => l.has_instagram).length,
  avg_lead_score:           leads.length
    ? Math.round(leads.reduce((s, l) => s + (l.lead_score || 0), 0) / leads.length)
    : 0,
};

const topLeads = [...leads]
  .sort((a, b) => (b.lead_score || 0) - (a.lead_score || 0))
  .slice(0, 10)
  .map(l => ({
    company_name:      l.company_name,
    website:           l.website,
    lead_score:        l.lead_score,
    pixel_id:          l.pixel_id,
    ad_status_summary: l.has_recent_inactive_ads
      ? 'Lapsed ads < 12m'
      : l.total_ads_found > 0 ? 'Older ad history'
      : 'No ad history',
    lead_reason:       l.lead_reason,
  }));

const summary = {
  generated_at: new Date().toISOString(),
  stats,
  top_10_leads: topLeads,
  all_leads: leads,
};

// Human-readable Slack/email summary
const slackText = [
  `*UK Travel Lead Finder – ${new Date().toLocaleDateString('en-GB')}*`,
  `Found *${stats.total_qualified_leads}* qualified leads`,
  `• ${stats.with_pixel} have a Meta Pixel installed`,
  `• ${stats.with_recent_ad_history} ran Meta ads in the last 12 months`,
  `• ${stats.no_ad_history} have never run Meta ads (pixel only)`,
  '',
  '*Top 5 leads:*',
  ...topLeads.slice(0, 5).map((l, i) =>
    `${i + 1}. ${l.company_name} – Score: ${l.lead_score} – ${l.ad_status_summary} – ${l.website}`
  ),
].join('\n');

return [{ json: { ...summary, slack_text: slackText } }];
